{
  "name": "Fiscais SP - Base de Conhecimento",
  "description": "Uma plataforma colaborativa para fiscais da Prefeitura de São Paulo compartilharem experiências, documentos e alertas de campo organizados por Posturas e Subprefeituras."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type PosturaType = 
  | 'Todas'
  | 'Obras' 
  | 'MPL' 
  | 'Atividades' 
  | 'Ambulantes' 
  | 'Publicidade' 
  | 'Área Pública' 
  | 'Outras';

export type ContentType = 'Dica' | 'Resumo' | 'Risco' | 'Documento';

export interface Post {
  id: string;
  postura: PosturaType;
  subprefeitura: string; // ID of the subprefeitura
  title: string;
  content: string;
  address?: string;
  author?: string;
  type: ContentType;
  createdAt: number;
  fileName?: string; // Simulated file attachment name
}

export interface Subprefeitura {
  id: string;
  name: string;
  region: 'Centro' | 'Norte' | 'Sul' | 'Leste' | 'Oeste';
}

import React from 'react';
import { Post, Subprefeitura } from '../types';
import { SUBPREFEITURAS, CONTENT_TYPES } from '../constants';
import { MapPin, User, AlertTriangle, FileText, Lightbulb, StickyNote, Trash2 } from 'lucide-react';

interface PostCardProps {
  post: Post;
  onDelete: (id: string) => void;
}

const PostCard: React.FC<PostCardProps> = ({ post, onDelete }) => {
  const subprefeituraName = SUBPREFEITURAS.find(s => s.id === post.subprefeitura)?.name || 'Desconhecida';
  const typeConfig = CONTENT_TYPES.find(c => c.value === post.type) || CONTENT_TYPES[1];

  const getIcon = () => {
    switch (post.type) {
      case 'Risco': return <AlertTriangle className="w-5 h-5" />;
      case 'Dica': return <Lightbulb className="w-5 h-5" />;
      case 'Documento': return <FileText className="w-5 h-5" />;
      default: return <StickyNote className="w-5 h-5" />;
    }
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('Tem certeza que deseja remover este item?')) {
      onDelete(post.id);
    }
  };

  return (
    <div className={`bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow duration-200 flex flex-col h-full ${post.type === 'Risco' ? 'border-l-4 border-l-red-500' : ''}`}>
      <div className="p-5 flex-1">
        <div className="flex justify-between items-start mb-3">
          <div className="flex gap-2 items-center flex-wrap">
            <span className={`inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-xs font-medium ${typeConfig.color}`}>
              {getIcon()}
              {typeConfig.label}
            </span>
            <span className="bg-slate-100 text-slate-600 text-xs px-2 py-0.5 rounded-full border border-slate-200">
              {post.postura}
            </span>
          </div>
          <button onClick={handleDelete} className="text-slate-300 hover:text-red-500 transition-colors">
            <Trash2 className="w-4 h-4" />
          </button>
        </div>

        <h3 className="font-bold text-slate-800 text-lg mb-2 leading-tight">{post.title}</h3>

        <p className="text-slate-600 text-sm mb-4 whitespace-pre-wrap line-clamp-6">
          {post.content}
        </p>

        {post.fileName && (
          <div className="bg-slate-50 border border-slate-200 rounded p-2 mb-3 flex items-center gap-2">
            <FileText className="w-4 h-4 text-slate-500" />
            <span className="text-xs text-slate-700 font-medium truncate">{post.fileName}</span>
          </div>
        )}
      </div>

      <div className="bg-slate-50 px-5 py-3 border-t border-slate-100 mt-auto">
        <div className="flex flex-col gap-1.5">
          <div className="flex items-center gap-1.5 text-xs text-slate-500 font-medium">
            <span className="w-2 h-2 rounded-full bg-indigo-500"></span>
            {subprefeituraName}
          </div>

          {post.address && (
            <div className="flex items-center gap-1.5 text-xs text-slate-500">
              <MapPin className="w-3 h-3" />
              <span className="truncate">{post.address}</span>
            </div>
          )}

          <div className="flex justify-between items-center mt-2 pt-2 border-t border-slate-200">
             <div className="flex items-center gap-1.5 text-xs text-slate-400">
              <User className="w-3 h-3" />
              <span>{post.author || 'Anônimo'}</span>
            </div>
            <span className="text-[10px] text-slate-400 uppercase tracking-wider">
              {new Date(post.createdAt).toLocaleDateString('pt-BR')}
            </span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PostCard;

import React, { useState } from 'react';
import { Post, PosturaType, ContentType } from '../types';
import { POSTURAS, SUBPREFEITURAS, CONTENT_TYPES } from '../constants';
import { X, Upload } from 'lucide-react';

interface CreateModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (post: Omit<Post, 'id' | 'createdAt'>) => void;
  defaultSubprefeitura: string;
  defaultPostura: string;
}

const CreateModal: React.FC<CreateModalProps> = ({ 
  isOpen, 
  onClose, 
  onSubmit, 
  defaultSubprefeitura,
  defaultPostura 
}) => {
  const [postura, setPostura] = useState<PosturaType>(
    (defaultPostura !== 'Todas' ? defaultPostura as PosturaType : 'Obras')
  );
  const [subprefeitura, setSubprefeitura] = useState<string>(
    defaultSubprefeitura !== 'all' ? defaultSubprefeitura : 'se'
  );
  const [type, setType] = useState<ContentType>('Resumo');
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [address, setAddress] = useState('');
  const [author, setAuthor] = useState('');
  const [fileName, setFileName] = useState<string | undefined>(undefined);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({
      postura,
      subprefeitura,
      type,
      title,
      content,
      address,
      author,
      fileName
    });
    // Reset form
    setTitle('');
    setContent('');
    setAddress('');
    setAuthor('');
    setFileName(undefined);
    onClose();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      setFileName(e.target.files[0].name);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
        <div className="p-4 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-10">
          <h2 className="text-xl font-bold text-slate-800">Novo Registro</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Postura</label>
              <select 
                value={postura} 
                onChange={(e) => setPostura(e.target.value as PosturaType)}
                className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                {POSTURAS.filter(p => p !== 'Todas').map(p => (
                  <option key={p} value={p}>{p}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Subprefeitura</label>
              <select 
                value={subprefeitura} 
                onChange={(e) => setSubprefeitura(e.target.value)}
                className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                {SUBPREFEITURAS.filter(s => s.id !== 'all').map(s => (
                  <option key={s.id} value={s.id}>{s.name}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Tipo de Conteúdo</label>
            <div className="grid grid-cols-2 gap-2">
              {CONTENT_TYPES.map(ct => (
                <button
                  key={ct.value}
                  type="button"
                  onClick={() => setType(ct.value as ContentType)}
                  className={`p-2 rounded-lg text-xs font-medium border transition-all ${
                    type === ct.value 
                      ? 'bg-indigo-600 text-white border-indigo-600 shadow-md transform scale-[1.02]' 
                      : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-300'
                  }`}
                >
                  {ct.label}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Título / Assunto</label>
            <input 
              type="text" 
              required
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="Ex: Obra irregular na Rua X"
              className="w-full p-3 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>

          <div>
            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Conteúdo</label>
            <textarea 
              required
              value={content}
              onChange={(e) => setContent(e.target.value)}
              rows={5}
              placeholder="Descreva a situação, dica ou procedimento..."
              className="w-full p-3 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
            ></textarea>
          </div>

          <div>
            <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Endereço (Opcional)</label>
            <input 
              type="text" 
              value={address}
              onChange={(e) => setAddress(e.target.value)}
              placeholder="Rua, Número, Referência"
              className="w-full p-3 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>

           <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Anexo (Simulado)</label>
                <div className="relative">
                  <input 
                    type="file" 
                    id="file-upload"
                    className="hidden" 
                    onChange={handleFileChange}
                  />
                  <label 
                    htmlFor="file-upload" 
                    className="flex items-center justify-center gap-2 w-full p-2.5 bg-slate-50 border border-slate-300 border-dashed rounded-lg text-xs cursor-pointer hover:bg-slate-100 transition-colors text-slate-600"
                  >
                    <Upload className="w-4 h-4" />
                    <span className="truncate">{fileName || 'Escolher arquivo'}</span>
                  </label>
                </div>
              </div>
              <div>
                 <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Autor (Opcional)</label>
                <input 
                  type="text" 
                  value={author}
                  onChange={(e) => setAuthor(e.target.value)}
                  placeholder="Seu nome"
                  className="w-full p-3 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                />
              </div>
           </div>

          <div className="pt-4 border-t border-slate-100 flex gap-3">
            <button 
              type="button" 
              onClick={onClose}
              className="flex-1 py-3 px-4 bg-slate-100 text-slate-700 font-medium rounded-lg hover:bg-slate-200 transition-colors"
            >
              Cancelar
            </button>
            <button 
              type="submit" 
              className="flex-1 py-3 px-4 bg-indigo-600 text-white font-medium rounded-lg hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-colors"
            >
              Publicar
            </button>
          </div>

        </form>
      </div>
    </div>
  );
};

export default CreateModal;

import React, { useState, useEffect, useMemo } from 'react';
import { POSTURAS, SUBPREFEITURAS } from './constants';
import { Post, PosturaType } from './types';
import PostCard from './components/PostCard';
import CreateModal from './components/CreateModal';
import { 
  Plus, 
  Search, 
  Map, 
  Menu, 
  Filter, 
  LayoutGrid,
  MapPin,
  X
} from 'lucide-react';

const LOCAL_STORAGE_KEY = 'fiscais-sp-db';

// Initial dummy data to populate the app if empty
const INITIAL_DATA: Post[] = [
  {
    id: '1',
    postura: 'Obras',
    subprefeitura: 'se',
    title: 'Tapume irregular na Pç. da Sé',
    content: 'Obra sem placa de identificação utilizando mais de 50% do passeio. Notificado em 10/10.',
    type: 'Resumo',
    address: 'Praça da Sé, 100',
    createdAt: Date.now() - 10000000,
    author: 'Fiscal João'
  },
  {
    id: '2',
    postura: 'Ambulantes',
    subprefeitura: 'lapa',
    title: 'Ponto viciado de comércio irregular',
    content: 'Atenção ao realizar fiscalização na Rua Doze de Outubro após as 18h. Grupo hostil recorrente.',
    type: 'Risco',
    address: 'Rua Doze de Outubro',
    createdAt: Date.now() - 5000000,
    author: 'Equipe Noturna'
  },
  {
    id: '3',
    postura: 'MPL',
    subprefeitura: 'pinheiros',
    title: 'Manual de Procedimentos - Limpeza',
    content: 'Arquivo PDF contendo o fluxo atualizado de multas para descarte irregular de entulho.',
    type: 'Documento',
    fileName: 'manual_mpl_2024.pdf',
    createdAt: Date.now(),
    author: 'Coordenação'
  }
];

export default function App() {
  // State
  const [posts, setPosts] = useState<Post[]>([]);
  const [selectedPostura, setSelectedPostura] = useState<PosturaType>('Todas');
  const [selectedSubprefeitura, setSelectedSubprefeitura] = useState<string>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Load from local storage
  useEffect(() => {
    const savedData = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (savedData) {
      setPosts(JSON.parse(savedData));
    } else {
      setPosts(INITIAL_DATA);
    }
  }, []);

  // Save to local storage
  useEffect(() => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(posts));
  }, [posts]);

  // Handlers
  const handleAddPost = (newPostData: Omit<Post, 'id' | 'createdAt'>) => {
    const newPost: Post = {
      ...newPostData,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    setPosts(prev => [newPost, ...prev]);
  };

  const handleDeletePost = (id: string) => {
    setPosts(prev => prev.filter(p => p.id !== id));
  };

  // Filtering Logic
  const filteredPosts = useMemo(() => {
    return posts.filter(post => {
      const matchPostura = selectedPostura === 'Todas' || post.postura === selectedPostura;
      const matchSub = selectedSubprefeitura === 'all' || post.subprefeitura === selectedSubprefeitura;
      const matchSearch = searchTerm === '' || 
        post.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
        post.content.toLowerCase().includes(searchTerm.toLowerCase()) ||
        post.address?.toLowerCase().includes(searchTerm.toLowerCase());

      return matchPostura && matchSub && matchSearch;
    });
  }, [posts, selectedPostura, selectedSubprefeitura, searchTerm]);

  const currentSubprefeituraName = SUBPREFEITURAS.find(s => s.id === selectedSubprefeitura)?.name;

  return (
    <div className="min-h-screen bg-slate-100 flex flex-col md:flex-row">

      {/* Mobile Header */}
      <div className="md:hidden bg-indigo-900 text-white p-4 sticky top-0 z-30 shadow-md flex justify-between items-center">
        <div className="flex items-center gap-2">
           <LayoutGrid className="w-6 h-6 text-indigo-300" />
           <span className="font-bold text-lg">Fiscais SP</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Sidebar (Desktop) / Drawer (Mobile) */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-slate-900 text-slate-300 transform transition-transform duration-300 ease-in-out md:translate-x-0 md:static md:h-screen overflow-y-auto border-r border-slate-800
        ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6 border-b border-slate-800 hidden md:block">
           <div className="flex items-center gap-2 text-white mb-1">
             <LayoutGrid className="w-6 h-6 text-indigo-500" />
             <span className="font-bold text-xl tracking-tight">Fiscais SP</span>
           </div>
           <p className="text-xs text-slate-500">Base Colaborativa</p>
        </div>

        <div className="p-4">
          <div className="mb-4">
            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2 px-2">Subprefeituras</h3>
            <div className="relative">
               <Search className="absolute left-3 top-2.5 w-4 h-4 text-slate-500" />
               <input 
                  type="text" 
                  placeholder="Filtrar região..." 
                  className="w-full bg-slate-800 border border-slate-700 rounded-lg py-2 pl-9 pr-3 text-sm focus:outline-none focus:border-indigo-500 text-slate-200 placeholder-slate-500"
               />
            </div>
          </div>

          <nav className="space-y-0.5">
            {SUBPREFEITURAS.map(sub => (
              <button
                key={sub.id}
                onClick={() => {
                  setSelectedSubprefeitura(sub.id);
                  setIsMobileMenuOpen(false);
                }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors ${
                  selectedSubprefeitura === sub.id 
                    ? 'bg-indigo-600 text-white' 
                    : 'hover:bg-slate-800 hover:text-white'
                }`}
              >
                <MapPin className={`w-4 h-4 ${selectedSubprefeitura === sub.id ? 'text-indigo-200' : 'text-slate-500'}`} />
                <span className="truncate text-left flex-1">{sub.name}</span>
                {selectedSubprefeitura === sub.id && <div className="w-1.5 h-1.5 rounded-full bg-indigo-200"></div>}
              </button>
            ))}
          </nav>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-[calc(100vh-60px)] md:h-screen overflow-hidden">

        {/* Top Navigation Bar */}
        <header className="bg-white border-b border-slate-200 sticky top-0 z-20 shadow-sm">
          <div className="px-6 py-4 flex flex-col gap-4">

            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <div>
                <h1 className="text-2xl font-bold text-slate-900 leading-tight">
                  {currentSubprefeituraName}
                </h1>
                <p className="text-sm text-slate-500">
                  {filteredPosts.length} registros encontrados
                </p>
              </div>

              <div className="flex items-center gap-3 w-full md:w-auto">
                <div className="relative flex-1 md:w-64">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                  <input
                    type="text"
                    placeholder="Buscar assunto, rua..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-9 pr-4 py-2 bg-slate-100 border-transparent focus:bg-white border focus:border-indigo-500 rounded-lg text-sm transition-all outline-none"
                  />
                </div>
                <button 
                  onClick={() => setIsModalOpen(true)}
                  className="bg-indigo-600 hover:bg-indigo-700 text-white p-2 md:px-4 md:py-2 rounded-lg flex items-center gap-2 shadow-lg shadow-indigo-200 transition-all active:scale-95 whitespace-nowrap"
                >
                  <Plus className="w-5 h-5" />
                  <span className="hidden md:inline font-medium">Novo Registro</span>
                </button>
              </div>
            </div>

            {/* Postura Tabs - Horizontal Scroll */}
            <div className="flex gap-1 overflow-x-auto no-scrollbar pb-1 -mx-6 px-6 md:mx-0 md:px-0 border-t border-slate-100 pt-4 md:pt-0 md:border-t-0">
              {POSTURAS.map(postura => (
                <button
                  key={postura}
                  onClick={() => setSelectedPostura(postura)}
                  className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-all border ${
                    selectedPostura === postura
                      ? 'bg-slate-900 text-white border-slate-900'
                      : 'bg-white text-slate-600 border-slate-200 hover:border-slate-300 hover:bg-slate-50'
                  }`}
                >
                  {postura}
                </button>
              ))}
            </div>
          </div>
        </header>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 bg-slate-50/50">

          {filteredPosts.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-center">
              <div className="bg-slate-100 p-4 rounded-full mb-4">
                <Filter className="w-8 h-8 text-slate-400" />
              </div>
              <h3 className="text-lg font-semibold text-slate-700 mb-1">Nenhum registro encontrado</h3>
              <p className="text-slate-500 max-w-sm">
                Não há conteúdo para a Postura e Subprefeitura selecionadas ou sua busca não retornou resultados.
              </p>
              <button 
                onClick={() => {
                    setSelectedPostura('Todas');
                    setSelectedSubprefeitura('all');
                    setSearchTerm('');
                }}
                className="mt-4 text-indigo-600 font-medium hover:underline"
              >
                Limpar filtros
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 md:gap-6">
              {filteredPosts.map(post => (
                <PostCard 
                  key={post.id} 
                  post={post} 
                  onDelete={handleDeletePost}
                />
              ))}
            </div>
          )}
        </div>
      </main>

      {/* Modal */}
      <CreateModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleAddPost}
        defaultSubprefeitura={selectedSubprefeitura}
        defaultPostura={selectedPostura}
      />
    </div>
  );
}

