interface CreateModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (post: any) => void; // Using any here to simplify Partial<Post> handling
  defaultSubprefeitura: string;
  defaultPostura: string;
  initialData?: Post | null;
}

const CreateModal: React.FC<CreateModalProps> = ({ 
  isOpen, 
  onClose, 
  onSubmit, 
  defaultSubprefeitura,
  defaultPostura,
  initialData
}) => {
  const [postura, setPostura] = useState<PosturaType>('Obras');
  const [subprefeitura, setSubprefeitura] = useState<string>('se');
  const [type, setType] = useState<ContentType>('Resumo');
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [address, setAddress] = useState('');
  const [author, setAuthor] = useState('');
  const [fileName, setFileName] = useState<string | undefined>(undefined);

  // Initialize form when opening
  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setPostura(initialData.postura);
        setSubprefeitura(initialData.subprefeitura);
        setType(initialData.type);
        setTitle(initialData.title);
        setContent(initialData.content);
        setAddress(initialData.address || '');
        setAuthor(initialData.author || '');
        setFileName(initialData.fileName);
      } else {
        // Reset for new entry
        setPostura((defaultPostura !== 'Todas' ? defaultPostura as PosturaType : 'Obras'));
        setSubprefeitura(defaultSubprefeitura !== 'all' ? defaultSubprefeitura : 'se');
        setType('Resumo');
        setTitle('');
        setContent('');
        setAddress('');
        setAuthor('');
        setFileName(undefined);
      }
    }
  }, [isOpen, initialData, defaultSubprefeitura, defaultPostura]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const postData = {
      postura,
      subprefeitura,
      type,
      title,
      content,
      address,
      author,
      fileName
    };

    if (initialData) {
      onSubmit({ ...postData, id: initialData.id, createdAt: initialData.createdAt });
    } else {
      onSubmit(postData);
    }

    onClose();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      setFileName(e.target.files[0].name);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto animate-in fade-in zoom-in-95 duration-200">
        <div className="p-4 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-10">
          <h2 className="text-xl font-bold text-slate-800">
            {initialData ? 'Editar Registro' : 'Novo Registro'}
          </h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Postura</label>
              <select 
                value={postura} 
                onChange={(e) => setPostura(e.target.value as PosturaType)}
                className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none transition-shadow"
              >
                {POSTURAS.filter(p => p !== 'Todas').map(p => (
                  <option key={p} value={p}>{p}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Subprefeitura</label>
              <select 
                value={subprefeitura} 
                onChange={(e) => setSubprefeitura(e.target.value)}
                className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none transition-shadow"
              >
                {SUBPREFEITURAS.filter(s => s.id !== 'all').map(s => (
                  <option key={s.id} value={s.id}>{s.name}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Tipo de Conteúdo</label>
            <div className="grid grid-cols-2 gap-2">
              {CONTENT_TYPES.map(ct => (
                <button
                  key={ct.value}
                  type="button"
                  onClick={() => setType(ct.value as ContentType)}
                  className={`p-2 rounded-lg text-xs font-bold border transition-all ${
                    type === ct.value 
                      ? 'bg-indigo-600 text-white border-indigo-600 shadow-md transform scale-[1.02]' 
                      : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-300 hover:bg-indigo-50'
                  }`}
                >
                  {ct.label}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Título / Assunto</label>
            <input 
              type="text" 
              required
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="Ex: Obra irregular na Rua X"
              className="w-full p-3 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-shadow placeholder:text-slate-400"
            />
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Conteúdo</label>
            <textarea 
              required
              value={content}
              onChange={(e) => setContent(e.target.value)}
              rows={5}
              placeholder="Descreva a situação, dica ou procedimento..."
              className="w-full p-3 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none transition-shadow placeholder:text-slate-400"
            ></textarea>
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Endereço (Opcional)</label>
            <input 
              type="text" 
              value={address}
              onChange={(e) => setAddress(e.target.value)}
              placeholder="Rua, Número, Referência"
              className="w-full p-3 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-shadow placeholder:text-slate-400"
            />
          </div>

           <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Anexo (Simulado)</label>
                <div className="relative">
                  <input 
