                  >
                    <Upload className="w-4 h-4" />
                    <span className="truncate">{fileName || 'Escolher arquivo'}</span>
                  </label>
                </div>
              </div>
              <div>
                 <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Autor (Opcional)</label>
                <input 
                  type="text" 
                  value={author}
                  onChange={(e) => setAuthor(e.target.value)}
                  placeholder="Seu nome"
                  className="w-full p-3 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-shadow placeholder:text-slate-400"
                />
              </div>
           </div>

          <div className="pt-4 border-t border-slate-100 flex gap-3">
            <button 
              type="button" 
              onClick={onClose}
              className="flex-1 py-3 px-4 bg-slate-100 text-slate-700 font-bold rounded-lg hover:bg-slate-200 transition-colors"
            >
              Cancelar
            </button>
            <button 
              type="submit" 
              className="flex-1 py-3 px-4 bg-indigo-600 text-white font-bold rounded-lg hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-colors flex items-center justify-center gap-2"
            >
              <Save className="w-4 h-4" />
              {initialData ? 'Salvar Alterações' : 'Publicar'}
            </button>
          </div>

        </form>
      </div>
    </div>
  );
};

