           <div className="flex items-center gap-2 text-white mb-1">
             <LayoutGrid className="w-7 h-7 text-indigo-500" />
             <span className="font-extrabold text-2xl tracking-tight">Fiscais SP</span>
           </div>
           <p className="text-xs text-slate-500 font-medium">Base de Conhecimento Operacional</p>
        </div>

