                  placeholder="Filtrar região..." 
                  className="w-full bg-slate-800 border border-slate-700 rounded-lg py-2 pl-9 pr-3 text-sm focus:outline-none focus:border-indigo-500 text-slate-200 placeholder-slate-500 transition-colors"
               />
            </div>
          </div>

          <nav className="space-y-0.5 overflow-y-auto flex-1 pr-2 no-scrollbar">
            {filteredSubprefeituras.map(sub => (
              <button
