export type PosturaType = 
  | 'Todas'
  | 'Obras' 
  | 'MPL' 
  | 'Atividades' 
  | 'Ambulantes' 
  | 'Publicidade' 
  | 'Área Pública' 
  | 'POP'
  | 'Defesa Civil'
  | 'Outras';

export type ContentType = 'Dica' | 'Resumo' | 'Risco' | 'Documento';

export interface Post {
  id: string;
  postura: PosturaType;
  subprefeitura: string; // ID of the subprefeitura
  title: string;
  content: string;
  address?: string;
  author?: string;
  type: ContentType;
  createdAt: number;
  fileName?: string; // Simulated file attachment name
}

export interface Subprefeitura {
  id: string;
  name: string;
  region: 'Centro' | 'Norte' | 'Sul' | 'Leste' | 'Oeste';
}

import React, { useState, useEffect, useMemo } from 'react';
import { POSTURAS, SUBPREFEITURAS, POSTURA_COLORS } from './constants';
import { Post, PosturaType } from './types';
import PostCard from './components/PostCard';
import CreateModal from './components/CreateModal';
import ViewModal from './components/ViewModal';
import { db } from './firebase';
import { collection, addDoc, getDocs, deleteDoc, doc, updateDoc, query, orderBy } from 'firebase/firestore';
import { 
  Plus, 
  Search, 
  Map, 
  Menu, 
  Filter, 
  LayoutGrid,
  MapPin,
  X,
  TrendingUp,
  FileCheck,
  Building2
} from 'lucide-react';

export default function App() {
  // State
  const [posts, setPosts] = useState<Post[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedPostura, setSelectedPostura] = useState<PosturaType>('Todas');
  const [selectedSubprefeitura, setSelectedSubprefeitura] = useState<string>('all');
  const [subSearchTerm, setSubSearchTerm] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isViewModalOpen, setIsViewModalOpen] = useState(false);
  const [editingPost, setEditingPost] = useState<Post | null>(null);
  const [viewingPost, setViewingPost] = useState<Post | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Fetch from Firebase
  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const q = query(collection(db, "posts"), orderBy("createdAt", "desc"));
        const querySnapshot = await getDocs(q);
        const fetchedPosts = querySnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        })) as Post[];
        setPosts(fetchedPosts);
      } catch (error) {
        console.error("Error fetching documents: ", error);
        // Fallback or alert could go here
      } finally {
        setLoading(false);
      }
    };

    fetchPosts();
