import React, { useState, useEffect } from 'react';
import { Post, PosturaType, ContentType } from '../types';
import { POSTURAS, SUBPREFEITURAS, CONTENT_TYPES } from '../constants';
import { X, Upload, Save, Loader2 } from 'lucide-react';

interface CreateModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (post: any) => Promise<void>; // Ensure it waits for async operation
  defaultSubprefeitura: string;
  defaultPostura: string;
  initialData?: Post | null;
}

const CreateModal: React.FC<CreateModalProps> = ({ 
  isOpen, 
  onClose, 
  onSubmit, 
  defaultSubprefeitura,
  defaultPostura,
  initialData
}) => {
  const [postura, setPostura] = useState<PosturaType>('Obras');
  const [subprefeitura, setSubprefeitura] = useState<string>('se');
  const [type, setType] = useState<ContentType>('Resumo');
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [address, setAddress] = useState('');
  const [author, setAuthor] = useState('');
  const [fileName, setFileName] = useState<string | undefined>(undefined);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Initialize form when opening
  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setPostura(initialData.postura);
        setSubprefeitura(initialData.subprefeitura);
        setType(initialData.type);
        setTitle(initialData.title);
        setContent(initialData.content);
        setAddress(initialData.address || '');
        setAuthor(initialData.author || '');
        setFileName(initialData.fileName);
      } else {
        // Reset for new entry
        // Handle "Todas" edge case - default to 'Obras' if 'Todas' is selected
        const validPostura = defaultPostura === 'Todas' ? 'Obras' : defaultPostura;
        setPostura(validPostura as PosturaType);

        // Handle "all" edge case - default to 'se' if 'all' is selected
        const validSub = defaultSubprefeitura === 'all' ? 'se' : defaultSubprefeitura;
        setSubprefeitura(validSub);

        setType('Resumo');
        setTitle('');
        setContent('');
        setAddress('');
        setAuthor('');
        setFileName(undefined);
      }
    }
    setIsSubmitting(false);
  }, [isOpen, initialData, defaultSubprefeitura, defaultPostura]);

  if (!isOpen) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const postData = {
      postura,
      subprefeitura,
      type,
      title,
      content,
      address,
      author,
      fileName
    };

    try {
      if (initialData) {
