// Mock Firebase Firestore implementation using localStorage
// This replaces the real Firebase SDK dependencies which are missing in the environment.

const STORAGE_KEY = 'fiscais_sp_posts';

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const getLocalPosts = (): any[] => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : [];
  } catch (e) {
    return [];
  }
};

const setLocalPosts = (posts: any[]) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(posts));
};

export const db = {}; // Placeholder object

export const collection = (db: any, name: string) => {
  return { type: 'collection', name };
};

export const query = (collectionRef: any, ...constraints: any[]) => {
  return { type: 'query', collection: collectionRef, constraints };
};

export const orderBy = (field: string, direction: 'asc' | 'desc') => {
  return { type: 'orderBy', field, direction };
};

export const getDocs = async (queryObj: any) => {
  await delay(600);
  let posts = getLocalPosts();

  // Apply sorting if present in query
  if (queryObj && queryObj.constraints) {
    const orderByConstraint = queryObj.constraints.find((c: any) => c.type === 'orderBy');
    if (orderByConstraint) {
      const { field, direction } = orderByConstraint;
      posts.sort((a: any, b: any) => {
        if (a[field] < b[field]) return direction === 'asc' ? -1 : 1;
        if (a[field] > b[field]) return direction === 'asc' ? 1 : -1;
        return 0;
      });
    }
  }

  return {
    docs: posts.map((p: any) => ({
      id: p.id,
      data: () => p
    }))
  };
};

export const addDoc = async (collectionRef: any, data: any) => {
  await delay(600);
  const posts = getLocalPosts();
  const newId = Math.random().toString(36).substr(2, 9);
  const newPost = { ...data, id: newId };
  posts.push(newPost);
  setLocalPosts(posts);
  return { id: newId };
};

export const doc = (db: any, collectionName: string, id: string) => {
  return { id, collectionName };
};

export const deleteDoc = async (docRef: any) => {
  await delay(400);
  let posts = getLocalPosts();
  posts = posts.filter((p: any) => p.id !== docRef.id);
  setLocalPosts(posts);
};

export const updateDoc = async (docRef: any, data: any) => {
  await delay(400);
  let posts = getLocalPosts();
  posts = posts.map((p: any) => p.id === docRef.id ? { ...p, ...data } : p);
  setLocalPosts(posts);
};

