          setIsCreateModalOpen(false);
          setEditingPost(null);
        }}
        onSubmit={handleSavePost}
        defaultSubprefeitura={selectedSubprefeitura}
        defaultPostura={selectedPostura}
        initialData={editingPost}
      />

      <ViewModal 
        isOpen={isViewModalOpen}
        onClose={() => setIsViewModalOpen(false)}
        post={viewingPost}
      />
    </div>
  );
}

