import React, { useState, useEffect, useRef } from 'react';
import { Post, PosturaType, ContentType } from '../types';
import { POSTURAS, SUBPREFEITURAS, CONTENT_TYPES } from '../constants';
import { X, Upload, Save, Loader2 } from 'lucide-react';

interface CreateModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (post: any) => Promise<void>;
  defaultSubprefeitura: string;
  defaultPostura: string;
  initialData?: Post | null;
}

const CreateModal: React.FC<CreateModalProps> = ({ 
  isOpen, 
  onClose, 
  onSubmit, 
  defaultSubprefeitura,
  defaultPostura,
  initialData
}) => {
  const [postura, setPostura] = useState<PosturaType>('Obras');
  const [subprefeitura, setSubprefeitura] = useState<string>('se');
  const [type, setType] = useState<ContentType>('Resumo');
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [address, setAddress] = useState('');
  const [author, setAuthor] = useState('');
  const [fileName, setFileName] = useState<string | undefined>(undefined);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const modalRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setPostura(initialData.postura);
        setSubprefeitura(initialData.subprefeitura);
        setType(initialData.type);
        setTitle(initialData.title);
        setContent(initialData.content);
        setAddress(initialData.address || '');
        setAuthor(initialData.author || '');
        setFileName(initialData.fileName);
      } else {
        const validPostura = defaultPostura === 'Todas' ? 'Obras' : defaultPostura;
        setPostura(validPostura as PosturaType);
        const validSub = defaultSubprefeitura === 'all' ? 'se' : defaultSubprefeitura;
        setSubprefeitura(validSub);
        setType('Resumo');
        setTitle('');
        setContent('');
        setAddress('');
        setAuthor('');
        setFileName(undefined);
      }
    }
    setIsSubmitting(false);
  }, [isOpen, initialData, defaultSubprefeitura, defaultPostura]);

  const handleBackdropClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) onClose();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;
    setIsSubmitting(true);

    const postData = { postura, subprefeitura, type, title, content, address, author, fileName };

    try {
      if (initialData) {
        await onSubmit({ ...postData, id: initialData.id, createdAt: initialData.createdAt });
      } else {
        await onSubmit(postData);
      }
      onClose();
    } catch (error) {
      console.error("Failed to submit", error);
      alert("Erro ao publicar dados no Firebase.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-[2px]" onClick={handleBackdropClick}>
      <div ref={modalRef} className="bg-white rounded-2xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto animate-in fade-in zoom-in-95 duration-200">
        <div className="p-6 border-b border-slate-50 flex justify-between items-center sticky top-0 bg-white z-10">
          <h2 className="text-xl font-bold text-slate-800">{initialData ? 'Editar Registro' : 'Novo Registro'}</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400"><X className="w-5 h-5" /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Postura</label>
              <select value={postura} onChange={(e) => setPostura(e.target.value as PosturaType)} className="w-full p-3 bg-slate-50 border-none rounded-xl text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none">
                {POSTURAS.filter(p => p !== 'Todas').map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Subprefeitura</label>
              <select value={subprefeitura} onChange={(e) => setSubprefeitura(e.target.value)} className="w-full p-3 bg-slate-50 border-none rounded-xl text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none">
                {SUBPREFEITURAS.filter(s => s.id !== 'all').map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
              </select>
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">Tipo de Conteúdo</label>
            <div className="flex flex-wrap gap-2">
              {CONTENT_TYPES.filter(t => t.value !== 'Todas').map(ct => (
                <button key={ct.value} type="button" onClick={() => setType(ct.value as ContentType)} className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${type === ct.value ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}>
                  {ct.label}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Assunto</label>
            <input type="text" required value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Título do relato..." className="w-full p-3 bg-slate-50 border-none rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-shadow font-medium" />
          </div>

          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Detalhes</label>
            <textarea required value={content} onChange={(e) => setContent(e.target.value)} rows={4} placeholder="Descreva a situação..." className="w-full p-3 bg-slate-50 border-none rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none font-medium"></textarea>
          </div>

          <div className="pt-4 flex gap-4">
            <button type="button" onClick={onClose} disabled={isSubmitting} className="flex-1 py-3 text-slate-500 font-bold rounded-xl hover:bg-slate-100 transition-colors disabled:opacity-50">Cancelar</button>
            <button type="submit" disabled={isSubmitting} className="flex-1 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-md flex items-center justify-center gap-2 disabled:opacity-70">
              {isSubmitting ? <><Loader2 className="w-4 h-4 animate-spin" /> Publicando...</> : <><Save className="w-4 h-4" /> {initialData ? 'Atualizar' : 'Publicar Registro'}</>}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default CreateModal;

