  const [subSearchTerm, setSubSearchTerm] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isViewModalOpen, setIsViewModalOpen] = useState(false);
  const [editingPost, setEditingPost] = useState<Post | null>(null);
  const [viewingPost, setViewingPost] = useState<Post | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const q = query(collection(db, "posts"), orderBy("createdAt", "desc"));
        const querySnapshot = await getDocs(q);
        const fetchedPosts = querySnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        })) as Post[];
        setPosts(fetchedPosts);
      } catch (error) {
        console.error("Error fetching documents: ", error);
      } finally {
        setLoading(false);
      }
    };
    fetchPosts();
  }, []);

  const handleSavePost = async (postData: any) => {
    try {
      console.log("Attempting to save post:", postData);
      if (postData.id) {
        const postRef = doc(db, "posts", postData.id);
        await updateDoc(postRef, { ...postData });
        setPosts(prev => prev.map(p => p.id === postData.id ? { ...postData } : p));
      } else {
        const newPost = { ...postData, createdAt: Date.now() };
        const docRef = await addDoc(collection(db, "posts"), newPost);
        setPosts(prev => [{ ...newPost, id: docRef.id }, ...prev]);
      }
      return Promise.resolve();
    } catch (e) {
      console.error("Firebase save error: ", e);
      alert("Erro ao salvar no Firebase. Verifique se o banco de dados está online.");
      return Promise.reject(e);
    }
  };

  const handleDeletePost = async (id: string) => {
    try {
      await deleteDoc(doc(db, "posts", id));
      setPosts(prev => prev.filter(p => p.id !== id));
    } catch (e) {
      console.error("Error deleting: ", e);
    }
  };

  const handleEditClick = (post: Post) => {
    setEditingPost(post);
    setIsCreateModalOpen(true);
  };

  const handleViewClick = (post: Post) => {
    setViewingPost(post);
    setIsViewModalOpen(true);
  };

  const stats = useMemo(() => {
    const total = posts.length;
    const activeSubs = new Set(posts.map(p => p.subprefeitura)).size;
    const activeThemes = new Set(posts.map(p => p.postura)).size;
    const riskCount = posts.filter(p => p.type === 'Risco').length;

    return { total, activeSubs, activeThemes, riskCount };
  }, [posts]);

  const filteredPosts = useMemo(() => {
    return posts.filter(post => {
      const matchPostura = selectedPostura === 'Todas' || post.postura === selectedPostura;
      const matchType = selectedType === 'Todas' || post.type === selectedType;
      const matchSub = selectedSubprefeitura === 'all' || post.subprefeitura === selectedSubprefeitura;
      const matchSearch = searchTerm === '' || 
        post.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
        post.content.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (post.address && post.address.toLowerCase().includes(searchTerm.toLowerCase()));

      return matchPostura && matchType && matchSub && matchSearch;
    });
  }, [posts, selectedPostura, selectedType, selectedSubprefeitura, searchTerm]);

  const filteredSubprefeituras = useMemo(() => {
    return SUBPREFEITURAS.filter(sub => 
      sub.name.toLowerCase().includes(subSearchTerm.toLowerCase())
    );
  }, [subSearchTerm]);

  const getPosturaIcon = (name: string) => {
    switch (name) {
      case 'Todas': return <LayoutGrid className="w-4 h-4" />;
      case 'Obras': return <Building className="w-4 h-4" />;
      case 'MPL': return <ClipboardCheck className="w-4 h-4" />;
      case 'Atividades': return <Package className="w-4 h-4" />;
      case 'Ambulantes': return <Users className="w-4 h-4" />;
      case 'Publicidade': return <Megaphone className="w-4 h-4" />;
      case 'Área Pública': return <Trees className="w-4 h-4" />;
      case 'POP': return <UserCheck className="w-4 h-4" />;
      case 'Defesa Civil': return <ShieldAlert className="w-4 h-4" />;
      default: return <MoreHorizontal className="w-4 h-4" />;
    }
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] flex flex-col md:flex-row font-sans text-slate-900 overflow-hidden">

      {/* Mobile Header */}
      <div className="md:hidden bg-slate-900 text-white p-4 sticky top-0 z-30 flex justify-between items-center">
        <div className="flex items-center gap-2">
           <LayoutGrid className="w-6 h-6 text-blue-400" />
           <span className="font-semibold text-lg tracking-tight">Fiscais SP</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-72 bg-slate-900 text-slate-300 transform transition-transform duration-300 ease-in-out md:translate-x-0 md:static md:h-screen flex flex-col border-r border-slate-800
        ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6 border-b border-slate-800 hidden md:block shrink-0">
           <div className="flex items-center gap-2 text-white mb-1">
             <LayoutGrid className="w-7 h-7 text-indigo-500" />
             <span className="font-bold text-2xl tracking-tight">Fiscais SP</span>
           </div>
           <p className="text-xs text-slate-500 font-medium">Base de Conhecimento</p>
        </div>

        <div className="p-4 flex-1 overflow-hidden flex flex-col">
          <div className="mb-4 shrink-0 px-2">
            <h3 className="text-[10px] font-semibold text-slate-500 uppercase tracking-widest mb-3">Subprefeituras</h3>
            <div className="relative">
               <Search className="absolute left-3 top-2.5 w-4 h-4 text-slate-500" />
               <input 
                  type="text" 
                  value={subSearchTerm}
                  onChange={(e) => setSubSearchTerm(e.target.value)}
                  placeholder="Pesquisar..." 
                  className="w-full bg-slate-800 border border-slate-700 rounded-lg py-2 pl-9 pr-3 text-sm focus:outline-none focus:border-indigo-500 text-slate-200 placeholder-slate-500 transition-colors"
               />
            </div>
          </div>

          <nav className="space-y-0.5 overflow-y-auto flex-1 pr-2 no-scrollbar">
            {filteredSubprefeituras.map(sub => (
              <button
                key={sub.id}
                onClick={() => {
                  setSelectedSubprefeitura(sub.id);
                  setIsMobileMenuOpen(false);
                }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all duration-200 ${
                  selectedSubprefeitura === sub.id 
                    ? 'bg-indigo-600 text-white shadow-lg' 
                    : 'hover:bg-slate-800 hover:text-white'
                }`}
              >
                <MapPin className={`w-4 h-4 shrink-0 ${selectedSubprefeitura === sub.id ? 'text-indigo-200' : 'text-slate-500'}`} />
                <span className="truncate text-left flex-1">{sub.name}</span>
              </button>
            ))}
          </nav>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden">

        <header className="bg-white border-b border-slate-100 sticky top-0 z-20 shrink-0">
          <div className="px-8 py-6 flex flex-col gap-6">

            <div className="flex flex-col md:flex-row justify-between items-center gap-4">
              <div className="text-center md:text-left">
                <h1 className="text-2xl font-semibold text-slate-900 tracking-tight">
                  {SUBPREFEITURAS.find(s => s.id === selectedSubprefeitura)?.name}
                </h1>
                <p className="text-sm text-slate-500 font-medium">Painel Administrativo de Fiscalização</p>
              </div>

              <div className="flex items-center gap-4 w-full md:w-auto">
                <div className="relative flex-1 md:w-80">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                  <input
                    type="text"
                    placeholder="Buscar assunto..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border-none focus:ring-2 focus:ring-indigo-500 rounded-xl text-sm transition-all outline-none font-medium"
                  />
                </div>
                <button 
                  onClick={() => { setEditingPost(null); setIsCreateModalOpen(true); }}
                  className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-xl flex items-center gap-2 shadow-sm transition-all active:scale-95 font-medium text-sm"
                >
                  <Plus className="w-5 h-5" />
                  Novo Registro
                </button>
              </div>
            </div>

            {/* Dashboard Stats - 4 Cards */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
               <div className="bg-white p-5 rounded-2xl border border-slate-50 shadow-sm flex justify-between items-center">
                  <div>
                    <div className="text-[11px] font-medium text-slate-400 mb-1">Total de Contribuições</div>
                    <div className="text-2xl font-semibold text-slate-800 leading-none">{stats.total}</div>
                  </div>
                  <div className="p-3 bg-blue-50 text-blue-500 rounded-xl"><FileText className="w-5 h-5" /></div>
               </div>
               <div className="bg-white p-5 rounded-2xl border border-slate-50 shadow-sm flex justify-between items-center">
                  <div>
                    <div className="text-[11px] font-medium text-slate-400 mb-1">Subprefeituras Ativas</div>
                    <div className="text-2xl font-semibold text-slate-800 leading-none">{stats.activeSubs}</div>
                  </div>
                  <div className="p-3 bg-emerald-50 text-emerald-500 rounded-xl"><Users className="w-5 h-5" /></div>
               </div>
               <div className="bg-white p-5 rounded-2xl border border-slate-50 shadow-sm flex justify-between items-center">
                  <div>
                    <div className="text-[11px] font-medium text-slate-400 mb-1">Temas Ativos</div>
                    <div className="text-2xl font-semibold text-slate-800 leading-none">{stats.activeThemes}</div>
                  </div>
                  <div className="p-3 bg-purple-50 text-purple-500 rounded-xl"><TrendingUp className="w-5 h-5" /></div>
               </div>
               <div className="bg-white p-5 rounded-2xl border border-slate-50 shadow-sm flex justify-between items-center">
                  <div>
                    <div className="text-[11px] font-medium text-slate-400 mb-1">Relatos de Risco</div>
                    <div className="text-2xl font-semibold text-slate-800 leading-none">{stats.riskCount}</div>
                  </div>
                  <div className="p-3 bg-amber-50 text-amber-500 rounded-xl"><AlertTriangle className="w-5 h-5" /></div>
               </div>
            </div>

            {/* Centered Filters - No borders */}
            <div className="flex flex-col items-center gap-4">
              <div className="flex gap-2 overflow-x-auto no-scrollbar w-full justify-center px-4">
                {POSTURAS.map(postura => {
                  const isActive = selectedPostura === postura;
                  const colors = POSTURA_COLORS[postura];
                  return (
                    <button
                      key={postura}
                      onClick={() => setSelectedPostura(postura)}
                      className={`px-4 py-2 rounded-xl text-[13px] font-medium whitespace-nowrap transition-all flex items-center gap-2 border-none shadow-none ${
                        isActive ? colors.active : colors.inactive
                      }`}
                    >
                      <span className={isActive ? 'text-white' : colors.iconColor}>
                        {getPosturaIcon(postura)}
                      </span>
                      {postura}
                    </button>
                  );
                })}
              </div>

              <div className="flex gap-2 overflow-x-auto no-scrollbar w-full justify-center">
                {CONTENT_TYPES.map(type => {
                  const isActive = selectedType === type.value;
                  return (
                    <button
                      key={type.value}
                      onClick={() => setSelectedType(type.value)}
                      className={`px-5 py-1.5 rounded-lg text-xs font-medium whitespace-nowrap transition-all border-none shadow-none ${
                        isActive ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                      }`}
                    >
                      {type.label}
                    </button>
                  );
                })}
              </div>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 bg-[#f8fafc]">
          {loading ? (
            <div className="flex flex-col justify-center items-center h-full gap-4">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
              <p className="text-sm font-medium text-slate-400">Carregando dados...</p>
            </div>
          ) : filteredPosts.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-center">
              <Filter className="w-12 h-12 text-slate-200 mb-4" />
              <h3 className="text-lg font-medium text-slate-700">Nenhum registro encontrado</h3>
              <p className="text-slate-400 text-sm">Ajuste os filtros para carregar o conteúdo.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-20">
              {filteredPosts.map(post => (
                <PostCard key={post.id} post={post} onDelete={handleDeletePost} onEdit={handleEditClick} onView={handleViewClick} />
              ))}
            </div>
          )}
        </div>
      </main>

      <CreateModal 
        isOpen={isCreateModalOpen} onClose={() => { setIsCreateModalOpen(false); setEditingPost(null); }}
        onSubmit={handleSavePost} defaultSubprefeitura={selectedSubprefeitura} defaultPostura={selectedPostura} initialData={editingPost}
      />
      <ViewModal isOpen={isViewModalOpen} onClose={() => setIsViewModalOpen(false)} post={viewingPost} />
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Post, PosturaType, ContentType } from '../types';
import { POSTURAS, SUBPREFEITURAS, CONTENT_TYPES } from '../constants';
import { X, Upload, Save, Loader2, MapPin, User, FileText } from 'lucide-react';

interface CreateModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (post: any) => Promise<void>;
  defaultSubprefeitura: string;
  defaultPostura: string;
  initialData?: Post | null;
}

const CreateModal: React.FC<CreateModalProps> = ({ 
  isOpen, 
  onClose, 
  onSubmit, 
  defaultSubprefeitura,
  defaultPostura,
  initialData
}) => {
  const [postura, setPostura] = useState<PosturaType>('Obras');
  const [subprefeitura, setSubprefeitura] = useState<string>('se');
  const [type, setType] = useState<ContentType>('Resumo');
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [address, setAddress] = useState('');
  const [author, setAuthor] = useState('');
  const [fileName, setFileName] = useState<string | undefined>(undefined);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const modalRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setPostura(initialData.postura);
        setSubprefeitura(initialData.subprefeitura);
        setType(initialData.type);
        setTitle(initialData.title);
        setContent(initialData.content);
        setAddress(initialData.address || '');
        setAuthor(initialData.author || '');
        setFileName(initialData.fileName);
      } else {
        const validPostura = defaultPostura === 'Todas' ? 'Obras' : defaultPostura;
        setPostura(validPostura as PosturaType);
        const validSub = defaultSubprefeitura === 'all' ? 'se' : defaultSubprefeitura;
        setSubprefeitura(validSub);
        setType('Resumo');
        setTitle('');
        setContent('');
        setAddress('');
        setAuthor('');
        setFileName(undefined);
      }
    }
    setIsSubmitting(false);
  }, [isOpen, initialData, defaultSubprefeitura, defaultPostura]);

  const handleBackdropClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) onClose();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;
    setIsSubmitting(true);

    const postData = { postura, subprefeitura, type, title, content, address, author, fileName };

    try {
      console.log("Submitting modal form:", postData);
      await onSubmit(postData);
      console.log("Submit successful");
      onClose();
    } catch (error) {
      console.error("Failed to submit form:", error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      setFileName(e.target.files[0].name);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-[2px]" onClick={handleBackdropClick}>
      <div ref={modalRef} className="bg-white rounded-3xl shadow-xl w-full max-w-xl max-h-[90vh] overflow-y-auto animate-in fade-in zoom-in-95 duration-200 border border-slate-100">
        <div className="p-6 border-b border-slate-50 flex justify-between items-center sticky top-0 bg-white z-10">
          <h2 className="text-xl font-semibold text-slate-800">{initialData ? 'Editar Registro' : 'Novo Registro'}</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-50 rounded-full transition-colors text-slate-400"><X className="w-5 h-5" /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] font-semibold text-slate-400 uppercase tracking-widest mb-2">Postura</label>
              <select value={postura} onChange={(e) => setPostura(e.target.value as PosturaType)} className="w-full p-3 bg-slate-50 border-none rounded-xl text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none">
                {POSTURAS.filter(p => p !== 'Todas').map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-[10px] font-semibold text-slate-400 uppercase tracking-widest mb-2">Subprefeitura</label>
              <select value={subprefeitura} onChange={(e) => setSubprefeitura(e.target.value)} className="w-full p-3 bg-slate-50 border-none rounded-xl text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none">
                {SUBPREFEITURAS.filter(s => s.id !== 'all').map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
              </select>
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-semibold text-slate-400 uppercase tracking-widest mb-3">Tipo de Conteúdo</label>
            <div className="flex flex-wrap gap-2">
              {CONTENT_TYPES.filter(t => t.value !== 'Todas').map(ct => (
                <button key={ct.value} type="button" onClick={() => setType(ct.value as ContentType)} className={`px-4 py-2 rounded-lg text-xs font-medium transition-all ${type === ct.value ? 'bg-slate-800 text-white shadow-md' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}>
                  {ct.label}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-semibold text-slate-400 uppercase tracking-widest mb-2">Assunto / Título</label>
            <input type="text" required value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Título breve do registro..." className="w-full p-3 bg-slate-50 border-none rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-shadow font-medium" />
          </div>

          <div>
            <label className="block text-[10px] font-semibold text-slate-400 uppercase tracking-widest mb-2">Descrição Detalhada</label>
            <textarea required value={content} onChange={(e) => setContent(e.target.value)} rows={4} placeholder="Descreva os detalhes aqui..." className="w-full p-3 bg-slate-50 border-none rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none font-medium leading-relaxed"></textarea>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] font-semibold text-slate-400 uppercase tracking-widest mb-2">Endereço (Opcional)</label>
              <div className="relative">
                <MapPin className="absolute left-3 top-3 w-4 h-4 text-slate-400" />
                <input type="text" value={address} onChange={(e) => setAddress(e.target.value)} placeholder="Rua, Número..." className="w-full p-3 pl-10 bg-slate-50 border-none rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none font-medium" />
              </div>
            </div>
            <div>
              <label className="block text-[10px] font-semibold text-slate-400 uppercase tracking-widest mb-2">Autor (Opcional)</label>
              <div className="relative">
                <User className="absolute left-3 top-3 w-4 h-4 text-slate-400" />
                <input type="text" value={author} onChange={(e) => setAuthor(e.target.value)} placeholder="Seu nome..." className="w-full p-3 pl-10 bg-slate-50 border-none rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none font-medium" />
              </div>
            </div>
          </div>

          <div>
             <label className="block text-[10px] font-semibold text-slate-400 uppercase tracking-widest mb-2">Anexar Documento</label>
             <div className="relative group">
                <input type="file" id="modal-file" className="hidden" onChange={handleFileChange} />
                <label htmlFor="modal-file" className="w-full p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center cursor-pointer group-hover:bg-slate-100 group-hover:border-indigo-300 transition-all">
                  <Upload className="w-6 h-6 text-slate-400 group-hover:text-indigo-500 mb-2" />
                  <span className="text-xs font-medium text-slate-500 truncate max-w-full px-4">{fileName || 'Clique para selecionar arquivo'}</span>
                </label>
             </div>
          </div>

          <div className="pt-4 flex gap-4">
            <button type="button" onClick={onClose} disabled={isSubmitting} className="flex-1 py-3.5 text-slate-400 font-semibold rounded-2xl hover:bg-slate-50 transition-colors disabled:opacity-50">Cancelar</button>
            <button type="submit" disabled={isSubmitting} className="flex-1 py-3.5 bg-indigo-600 text-white font-semibold rounded-2xl hover:bg-indigo-700 shadow-md flex items-center justify-center gap-2 disabled:opacity-70">
              {isSubmitting ? <><Loader2 className="w-4 h-4 animate-spin" /> Processando...</> : <><Save className="w-4 h-4" /> {initialData ? 'Salvar Alterações' : 'Publicar Agora'}</>}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default CreateModal;

