                 {post.author || 'Anônimo'}
              </div>
              <div className="flex items-center gap-3 text-slate-500 text-xs">
                 <Calendar className="w-4 h-4 text-slate-300" />
                 {new Date(post.createdAt).toLocaleDateString('pt-BR')}
              </div>
            </div>
          </div>

          {/* Área de download/link do arquivo (exibido para todos os arquivos, mesmo imagens, para permitir download) */}
          {post.fileName && (
            <div className="p-4 bg-slate-50 rounded-2xl flex items-center justify-between gap-3 border border-slate-100">
              <div className="flex items-center gap-3">
